namespace sv_e4f215577d164e08b118a768b08e0cf4.Client.Services;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    string Status,
    string Location,
    DateTimeOffset Timestamp);

namespace sv_e4f215577d164e08b118a768b08e0cf4.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;

namespace sv_e4f215577d164e08b118a768b08e0cf4.Client.Services;

/// <summary>
/// Client-side implementation used when running on WebAssembly.
/// Calls the server API endpoint over HTTP.
/// </summary>
public sealed class HttpShipmentService(HttpClient http) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var shipment = await http.GetFromJsonAsync<Shipment>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return shipment ?? throw new InvalidOperationException("Shipment not found.");
    }
}

using sv_e4f215577d164e08b118a768b08e0cf4.Client.Services;

namespace sv_e4f215577d164e08b118a768b08e0cf4.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with fake data.
/// </summary>
public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Order Placed", "New York, NY", new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Picked Up", "New York, NY", new DateTimeOffset(2026, 5, 19, 8, 30, 0, TimeSpan.Zero)),
                new StatusUpdate("In Transit", "Chicago, IL", new DateTimeOffset(2026, 5, 21, 14, 15, 0, TimeSpan.Zero)),
            ]),

        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Order Placed", "Seattle, WA", new DateTimeOffset(2026, 5, 15, 9, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Shipped", "Seattle, WA", new DateTimeOffset(2026, 5, 16, 11, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("In Transit", "Portland, OR", new DateTimeOffset(2026, 5, 17, 16, 45, 0, TimeSpan.Zero)),
                new StatusUpdate("Out for Delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 7, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 11, 23, 0, TimeSpan.Zero)),
            ]),

        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates:
            [
                new StatusUpdate("Order Placed", "Dallas, TX", new DateTimeOffset(2026, 5, 22, 13, 0, 0, TimeSpan.Zero)),
            ]),
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (!SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
        }

        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_e4f215577d164e08b118a768b08e0cf4.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>

    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>

        <dt>Location</dt>
        <dd>@_shipment.Location</dd>

        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status History</h3>
    <table class="table">
        <thead>
            <tr>
                <th>Time</th>
                <th>Status</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Status</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();

        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

