{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        app.MapGet("api/shipments/{trackingNumber}", async (
            string trackingNumber,
            [FromServices] IShipmentService service,
            CancellationToken ct) =>
        {
            try
